import React, { useState, useCallback, useEffect, useRef } from 'react';
import type * as tf from '@tensorflow/tfjs';
import { TrainingConfigurator } from './components/TrainingConfigurator';
import { TrainingDashboard } from './components/TrainingDashboard';
import { InferenceTester } from './components/InferenceTester';
import { Header } from './components/Header';
import { ModelVisualizer } from './components/ModelVisualizer';
import { InfoModal } from './components/InfoModal';
import { WaveScape } from './components/WaveScape';
import { PruningModal } from './components/PruningModal';
import { createModel, trainModel, saveModel, loadModel, checkForSavedModel, deleteSavedModel, downloadModel, pruneModel } from './services/modelService';
import { MnistData } from './services/mnistData';
import type { ModelConfig, TrainingLog, ModelInfo, PruningInfo } from './types';
import { BrainCircuitIcon, PlayIcon, RocketIcon, SaveIcon, FolderDownIcon, TrashIcon, DownloadIcon, XIcon } from './constants';
import { analyzeModel } from './services/modelAnalysisService';
// Info Modal Content
import { AboutInfo } from './components/info-content/AboutInfo';
import { ArchitectureInfo } from './components/info-content/ArchitectureInfo';
import { LayersInfo } from './components/info-content/LayersInfo';
import { LearningRateInfo } from './components/info-content/LearningRateInfo';
import { EpochsBatchSizeInfo } from './components/info-content/EpochsBatchSizeInfo';

export interface TrainingRun {
    id: number;
    config: ModelConfig;
    log: TrainingLog[];
    model: tf.Sequential | null;
    modelInfo: ModelInfo | null;
    pruning?: PruningInfo;
    inputShape?: (number | null)[];
    modelJSON?: object;
}

const MAX_COMPLETED_RUNS = 3;

type Page = 'mnist' | 'wavescape';

const App: React.FC = () => {
    const [page, setPage] = useState<Page>('mnist');
    const [config, setConfig] = useState<ModelConfig>({
        layers: [{ units: 128, activation: 'relu' }],
        learningRate: 0.005,
        lrSchedule: 'cosine',
        epochs: 10,
        batchSize: 512,
        architecture: 'dense',
        dropoutRate: 0.25,
    });
    const [isTraining, setIsTraining] = useState(false);
    const [trainingLog, setTrainingLog] = useState<TrainingLog[]>([]);
    const [modelForTesting, setModelForTesting] = useState<tf.Sequential | null>(null);
    const [modelToVisualize, setModelToVisualize] = useState<tf.Sequential | null>(null);
    const [trainingStatus, setTrainingStatus] = useState('Ready to train.');
    const [savedModelExists, setSavedModelExists] = useState(false);
    const [completedRuns, setCompletedRuns] = useState<TrainingRun[]>([]);
    const [activeInfoModal, setActiveInfoModal] = useState<string | null>(null);
    const [currentModelInfo, setCurrentModelInfo] = useState<ModelInfo | null>(null);
    const [runToPrune, setRunToPrune] = useState<TrainingRun | null>(null);
    const stopTrainingRef = useRef(false);

    useEffect(() => {
        const checkModel = async () => {
            const exists = await checkForSavedModel();
            setSavedModelExists(exists);
        };
        checkModel();
    }, []);

    const handleStopTraining = useCallback(() => {
        stopTrainingRef.current = true;
        setTrainingStatus('Stopping training...');
    }, []);

    const runTrainingProcess = useCallback(async (
        modelToTrain: tf.Sequential,
        configForRun: ModelConfig,
        pruningInfo?: PruningInfo
    ) => {
        setIsTraining(true);
        setTrainingLog([]);
        setModelForTesting(null);
        setTrainingStatus('Initializing...');
        stopTrainingRef.current = false;

        const currentRunLog: TrainingLog[] = [];
        let model = modelToTrain;
        let modelInfo: ModelInfo | null = null;

        try {
            modelInfo = analyzeModel(model, configForRun);
            setCurrentModelInfo(modelInfo);

            setTrainingStatus('Loading MNIST dataset...');
            const data = await MnistData.getInstance();
            const { images: trainImages, labels: trainLabels } = data.getTrainData();
            const { images: testImages, labels: testLabels } = data.getValidationData();

            setTrainingStatus('Starting training...');
            await trainModel(
                model,
                trainImages,
                trainLabels,
                testImages,
                testLabels,
                configForRun,
                async (epoch, logs, lr) => {
                    if (stopTrainingRef.current && model) {
                        model.stopTraining = true;
                    }
                    const newLogEntry: TrainingLog = {
                        epoch: epoch + 1,
                        loss: logs.loss,
                        accuracy: logs.acc,
                        val_loss: logs.val_loss,
                        val_accuracy: logs.val_acc,
                        lr
                    };
                    currentRunLog.push(newLogEntry);

                    // Re-draw the graphs after each epoch is complete to ensure live updates
                    setTrainingLog([...currentRunLog]);

                    // Allow UI to render the new state
                    await new Promise(resolve => requestAnimationFrame(resolve));

                    if (!stopTrainingRef.current) {
                        setTrainingStatus(`Epoch ${epoch + 1}/${configForRun.epochs} complete...`);
                    }
                }
            );

            const finalStatus = stopTrainingRef.current 
                ? 'Training stopped by user.'
                : 'Training complete!';

            setTrainingStatus(finalStatus);

            // Capture metadata BEFORE storing in React state to prevent it from being stripped.
            const inputTensorShape = model.inputs[0]?.shape; 
            const inputShape = inputTensorShape ? inputTensorShape.slice(1) : undefined;
            const modelJSON = model.toJSON(null, false) as object;

            if (!inputShape) {
                console.error("Critical: Could not determine input shape from model.inputs after training.");
            }

            setCompletedRuns(prev => {
                const newRun: TrainingRun = {
                    id: Date.now(),
                    config: { ...configForRun },
                    log: currentRunLog,
                    model: model,
                    modelInfo: modelInfo,
                    inputShape: inputShape,
                    modelJSON: modelJSON,
                    ...(pruningInfo && { pruning: pruningInfo }),
                };
                const updatedRuns = [newRun, ...prev];
                return updatedRuns.slice(0, MAX_COMPLETED_RUNS);
            });

        } catch (error) {
            console.error('Training failed:', error);
            setTrainingStatus(`Error during training: ${error instanceof Error ? error.message : 'Unknown error'}`);
        } finally {
            setIsTraining(false);
            setTrainingLog([]);
            setCurrentModelInfo(null);
        }
    }, []);

    const handleStartTraining = useCallback(async () => {
        const newModel = createModel(config);
        newModel.summary();
        await runTrainingProcess(newModel, config);
    }, [config, runTrainingProcess]);

    const handleStartPruningAndFinetuning = useCallback(async (originalRun: TrainingRun, targetSparsity: number) => {
        setRunToPrune(null); // Close modal
        setTrainingStatus('Pruning model...');
        if (!originalRun.model || !originalRun.inputShape || !originalRun.modelJSON) {
            setTrainingStatus('Error: Original model metadata not available for pruning.');
            console.error("Pruning pre-requisites not met:", originalRun);
            return;
        }

        try {
            const { prunedModel, actualSparsity } = await pruneModel(originalRun.model, targetSparsity, originalRun.inputShape, originalRun.modelJSON);
            prunedModel.summary();

            const finetuneConfig: ModelConfig = {
                ...originalRun.config,
                epochs: 5, // Short fine-tuning run
                learningRate: 0.0001, // Low learning rate for fine-tuning
                lrSchedule: 'constant',
            };

            const pruningInfo: PruningInfo = {
                fromRunId: originalRun.id,
                sparsity: actualSparsity
            };

            setTrainingStatus('Starting fine-tuning...');
            await runTrainingProcess(prunedModel, finetuneConfig, pruningInfo);

        } catch (error) {
             console.error('Pruning failed:', error, error instanceof Error ? error.stack : '');
            setTrainingStatus(`Error during pruning: ${error instanceof Error ? error.message : 'Unknown error'}`);
        }

    }, [runTrainingProcess]);


    const handleSaveModel = useCallback(async () => {
        if (!modelForTesting) return;
        setTrainingStatus('Saving model to local storage...');
        try {
            await saveModel(modelForTesting);
            setSavedModelExists(true);
            setTrainingStatus('Model saved successfully!');
        } catch (error) {
            console.error('Failed to save model:', error);
            setTrainingStatus(`Error saving model: ${error instanceof Error ? error.message : 'Unknown error'}`);
        }
    }, [modelForTesting]);

    const handleDownloadModel = useCallback(async () => {
        if (!modelForTesting) return;
        setTrainingStatus('Preparing model for download...');
        try {
            await downloadModel(modelForTesting);
            setTrainingStatus('Model download started!');
        } catch (error) {
            console.error('Failed to download model:', error);
            setTrainingStatus(`Error downloading model: ${error instanceof Error ? error.message : 'Unknown error'}`);
        }
    }, [modelForTesting]);

    const handleLoadModel = useCallback(async () => {
        setTrainingStatus('Loading model from local storage...');
        try {
            const loadedModel = await loadModel();
            setModelForTesting(loadedModel);
            setTrainingStatus('Model loaded! Ready for testing.');
        } catch (error) {
            console.error('Failed to load model:', error);
            setTrainingStatus(`Error loading model: ${error instanceof Error ? error.message : 'Unknown error'}`);
        }
    }, []);

    const handleDeleteModel = useCallback(async () => {
        if (window.confirm('Are you sure you want to delete the saved model? This action cannot be undone.')) {
            setTrainingStatus('Deleting saved model...');
            try {
                await deleteSavedModel();
                setSavedModelExists(false);
                setTrainingStatus('Saved model deleted.');
                if(modelForTesting?.name === 'localstorage://mnist-model') {
                    setModelForTesting(null);
                }
            } catch (error) {
                console.error('Failed to delete model:', error);
                setTrainingStatus(`Error deleting model: ${error instanceof Error ? error.message : 'Unknown error'}`);
            }
        }
    }, [modelForTesting]);

    const handleClearRuns = () => {
        setCompletedRuns([]);
        setModelForTesting(null);
        setCurrentModelInfo(null);
    }

    const handlePruneRequest = (run: TrainingRun) => {
        setRunToPrune(run);
    };

    const handleShowInfo = (topic: string) => setActiveInfoModal(topic);
    const handleCloseInfo = () => setActiveInfoModal(null);

    const renderInfoModal = () => {
        if (!activeInfoModal) return null;

        let title = '';
        let content: React.ReactNode = null;

        switch (activeInfoModal) {
            case 'about':
                title = 'About This App';
                content = <AboutInfo />;
                break;
            case 'architecture':
                title = 'Understanding Model Architectures';
                content = <ArchitectureInfo />;
                break;
            case 'layers':
                title = 'Hidden Layers, Units, and Activations';
                content = <LayersInfo />;
                break;
            case 'lr':
                title = 'The Learning Rate & Schedules';
                content = <LearningRateInfo />;
                break;
            case 'epochs-batch':
                title = 'Epochs & Batch Size';
                content = <EpochsBatchSizeInfo />;
                break;
            default:
                return null;
        }

        return (
            <InfoModal title={title} onClose={handleCloseInfo}>
                {content}
            </InfoModal>
        );
    };

    const isIdle = !isTraining && trainingLog.length === 0 && completedRuns.length === 0;

    const renderMnistExplorer = () => (
        <main className="w-full max-w-7xl mx-auto grid grid-cols-1 lg:grid-cols-3 gap-8 mt-8">
            <div className="lg:col-span-1 space-y-8">
                <TrainingConfigurator 
                    config={config} 
                    setConfig={setConfig} 
                    onStartTraining={handleStartTraining} 
                    onStopTraining={handleStopTraining}
                    isTraining={isTraining} 
                    onShowInfo={handleShowInfo}
                />
                {savedModelExists && (
                     <div className="bg-white/10 border border-white/20 rounded-2xl p-6 space-y-4 shadow-2xl">
                        <h2 className="text-xl font-bold text-white">Manage Saved Model</h2>
                        <p className="text-sm text-gray-300">A trained model is available in your browser's local storage.</p>
                        <div className="flex flex-col sm:flex-row gap-4">
                            <button 
                                onClick={handleLoadModel} 
                                disabled={isTraining}
                                className="flex-1 bg-gradient-to-r from-green-500 to-emerald-500 hover:from-green-400 hover:to-emerald-400 text-white font-bold py-2 px-4 rounded-full flex items-center justify-center space-x-2 transition-all duration-300 transform hover:scale-105 disabled:opacity-50 disabled:cursor-wait"
                            >
                                <FolderDownIcon className="w-5 h-5"/>
                                <span>Load Model</span>
                            </button>
                            <button 
                                onClick={handleDeleteModel} 
                                disabled={isTraining}
                                className="flex-1 bg-gradient-to-r from-red-500 to-pink-500 hover:from-red-400 hover:to-pink-400 text-white font-bold py-2 px-4 rounded-full flex items-center justify-center space-x-2 transition-all duration-300 transform hover:scale-105 disabled:opacity-50"
                            >
                                <TrashIcon className="w-5 h-5"/>
                                <span>Delete Model</span>
                            </button>
                        </div>
                    </div>
                )}
            </div>
            <div className="lg:col-span-2 space-y-8">
                {isIdle ? (
                    <div className="bg-white/10 border border-white/20 rounded-2xl p-8 h-full flex flex-col justify-center items-center text-center shadow-2xl">
                        <BrainCircuitIcon className="w-24 h-24 text-cyan-300 mb-6" />
                        <h2 className="text-3xl font-bold mb-2 bg-clip-text text-transparent bg-gradient-to-r from-cyan-400 to-pink-500">Welcome to the ML Explorer</h2>
                        <p className="text-gray-300 max-w-md">Configure your neural network on the left, then click 'Start Training' to see it learn{savedModelExists && ", or load a previously saved model"}!</p>
                        {!isTraining && (
                            <button
                                onClick={handleStartTraining}
                                className="mt-8 bg-gradient-to-r from-cyan-500 to-blue-500 hover:from-cyan-400 hover:to-blue-400 text-white font-bold py-3 px-8 rounded-full flex items-center space-x-2 transition-all duration-300 transform hover:scale-105 shadow-lg"
                            >
                                <PlayIcon className="w-5 h-5" />
                                <span>Start First Training</span>
                            </button>
                        )}
                    </div>
                ) : (
                  <>
                    {completedRuns.length > 0 && (
                        <div className="flex justify-between items-center">
                            <h2 className="text-2xl font-bold text-white">Comparison Runs</h2>
                            <button onClick={handleClearRuns} className="flex items-center space-x-2 text-sm text-gray-400 hover:text-red-400 transition">
                                <TrashIcon className="w-4 h-4" />
                                <span>Clear All Runs</span>
                            </button>
                        </div>
                    )}

                    {(isTraining || trainingLog.length > 0) && (
                        <TrainingDashboard 
                            isLive={true}
                            trainingLog={trainingLog} 
                            config={config}
                            status={trainingStatus}
                            modelInfo={currentModelInfo}
                        />
                    )}

                    {completedRuns.map(run => {
                        const parentRun = run.pruning
                            ? completedRuns.find(p => p.id === run.pruning!.fromRunId)
                            : undefined;
                        return (
                            <TrainingDashboard 
                                key={run.id}
                                isLive={false}
                                run={run}
                                parentRun={parentRun}
                                onTestModel={() => setModelForTesting(run.model)}
                                onVisualizeModel={() => setModelToVisualize(run.model)}
                                isModelInTest={modelForTesting === run.model}
                                onPruneModel={handlePruneRequest}
                            />
                        );
                    })}
                  </>
                )}
                {modelForTesting && (
                   <div className="bg-white/10 border border-white/20 rounded-2xl p-8 shadow-2xl">
                     <div className="flex flex-col sm:flex-row items-center justify-between space-y-4 sm:space-y-0 sm:space-x-4 mb-6">
                       <div className="flex items-center space-x-4">
                         <RocketIcon className="w-10 h-10 text-pink-400" />
                         <div>
                           <h2 className="text-2xl font-bold text-white">Test Your Model</h2>
                           <p className="text-gray-300">Draw digits on the canvases below to see your model in action.</p>
                         </div>
                       </div>
                       <div className="flex flex-col sm:flex-row gap-3">
                        <button 
                            onClick={handleSaveModel}
                            className="w-full sm:w-auto bg-gradient-to-r from-violet-500 to-fuchsia-500 hover:from-violet-400 hover:to-fuchsia-400 text-white font-bold py-2 px-6 rounded-full flex items-center justify-center space-x-2 transition-all duration-300 transform hover:scale-105"
                        >
                            <SaveIcon className="w-5 h-5" />
                            <span>Save Model</span>
                        </button>
                        <button 
                            onClick={handleDownloadModel}
                            className="w-full sm:w-auto bg-gradient-to-r from-blue-500 to-teal-500 hover:from-blue-400 hover:to-teal-400 text-white font-bold py-2 px-6 rounded-full flex items-center justify-center space-x-2 transition-all duration-300 transform hover:scale-105"
                        >
                            <DownloadIcon className="w-5 h-5" />
                            <span>Download Model</span>
                        </button>
                        <button onClick={() => setModelForTesting(null)} className="w-full sm:w-auto bg-gray-600 hover:bg-gray-500 text-white font-bold py-2 px-6 rounded-full flex items-center justify-center space-x-2 transition-all duration-300">
                            <XIcon className="w-5 h-5" />
                            <span>Close</span>
                        </button>
                       </div>
                     </div>
                     <InferenceTester model={modelForTesting} />
                   </div>
                )}
            </div>
        </main>
    );

    const renderWaveScape = () => (
         <main className="w-full max-w-7xl mx-auto flex flex-col items-center gap-8 mt-8 px-4">
            <div className="text-center">
                <h2 className="text-3xl font-bold mb-2 bg-clip-text text-transparent bg-gradient-to-r from-teal-400 to-sky-500">Interactive Gradient Descent</h2>
                <p className="text-gray-300 max-w-3xl">
                    Explore advanced optimization techniques in a visual sandbox. The ball navigates a complex, procedurally generated loss landscape full of hills, valleys, and saddle points, trying to find the lowest point. Each time you press "New Landscape," a unique challenge is created. Go beyond simple gradient descent: switch to the powerful Adam optimizer, use the "Continuation" method to smooth the landscape, and add thermal noise with Langevin Dynamics to escape local minima. Experiment with these powerful tools to see how modern optimizers conquer challenging problems.
                </p>
            </div>
            <WaveScape />
          </main>
    );

    return (
        <div 
            className="min-h-screen w-full bg-black bg-cover bg-center bg-fixed text-white font-sans" 
            style={{ backgroundImage: `url('https://files.catbox.moe/w544w8.webp')` }}
        >
            {renderInfoModal()}

            {runToPrune && (
                <PruningModal 
                    run={runToPrune}
                    onClose={() => setRunToPrune(null)}
                    onStartFinetuning={handleStartPruningAndFinetuning}
                />
            )}

            {modelToVisualize ? (
                <ModelVisualizer model={modelToVisualize} onClose={() => setModelToVisualize(null)} />
            ) : (
                <div className="min-h-screen w-full bg-black/60 backdrop-blur-sm flex flex-col">
                    <div className="flex-grow flex flex-col items-center p-4 sm:p-8">
                        <Header onShowInfo={handleShowInfo} page={page} setPage={setPage} />
                        {page === 'mnist' ? renderMnistExplorer() : renderWaveScape()}
                    </div>
                    <footer className="w-full text-center p-4 text-xs text-gray-400">
                        App shared under a CC-BY-SA license by Morgan Andreasson
                    </footer>
                </div>
            )}
        </div>
    );
};

export default App;

import React from 'react';
import type { TrainingLog, ModelConfig, ModelInfo, PruningInfo } from '../types';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer } from 'recharts';
import { LEARNING_RATE_SCHEDULES } from '../constants';
import { RocketIcon, EyeIcon, InfoIcon, ChevronDownIcon, CutIcon } from '../constants';
import type { TrainingRun as FullTrainingRun } from '../App';


interface TrainingRun {
    id: number;
    config: ModelConfig;
    log: TrainingLog[];
    modelInfo: ModelInfo | null;
    pruning?: PruningInfo;
}

interface TrainingDashboardProps {
    isLive: boolean;
    status?: string;
    // Props for live run
    trainingLog?: TrainingLog[];
    config?: ModelConfig;
    modelInfo?: ModelInfo | null;
    // Props for completed run
    run?: TrainingRun;
    parentRun?: FullTrainingRun;
    onTestModel?: () => void;
    onVisualizeModel?: () => void;
    onPruneModel?: (run: FullTrainingRun) => void;
    isModelInTest?: boolean;
}

const getScheduleName = (id: string) => LEARNING_RATE_SCHEDULES.find(s => s.id === id)?.name || 'Unknown';

export const TrainingDashboard: React.FC<TrainingDashboardProps> = (props) => {
    const { isLive, status, onTestModel, onVisualizeModel, onPruneModel, isModelInTest, parentRun } = props;

    // Consolidate props for live vs completed runs
    const runData = isLive
        ? { log: props.trainingLog!, config: props.config!, modelInfo: props.modelInfo, pruning: undefined }
        : { log: props.run!.log, config: props.run!.config, modelInfo: props.run!.modelInfo, pruning: props.run!.pruning };

    const { log: trainingLog, config, modelInfo, pruning } = runData;

    const progress = trainingLog.length > 0 ? (trainingLog[trainingLog.length - 1].epoch / config.epochs) * 100 : (isLive ? 0 : 100);

    // Enable lastLog for live runs too so accuracy badges update in real-time
    const lastLog = trainingLog.length > 0 ? trainingLog[trainingLog.length - 1] : null;
    const currentAccuracy = lastLog ? (lastLog.val_accuracy ?? lastLog.accuracy) : null;
    const hasValidationData = lastLog && lastLog.val_accuracy !== undefined;

    let effectiveParams: number | null = null;
    let accuracyDiff: number | null = null;

    if (pruning && modelInfo) {
        effectiveParams = Math.round(modelInfo.totalParams * (1 - pruning.sparsity));
    }

    if (pruning && parentRun && currentAccuracy && parentRun.log.length > 0) {
        const parentLastLog = parentRun.log[parentRun.log.length - 1];
        if (parentLastLog) {
            const parentAccuracy = parentLastLog.val_accuracy ?? parentLastLog.accuracy;
            accuracyDiff = currentAccuracy - parentAccuracy;
        }
    }

    const title = pruning
        ? `Pruned Model (${(pruning.sparsity * 100).toFixed(0)}% sparse)`
        : (modelInfo?.name || (isLive ? "Live Training" : "Completed Run"));

    return (
        <div className={`bg-white/10 border rounded-2xl p-6 shadow-2xl transition-all duration-300 ${isLive ? 'border-cyan-400/50' : 'border-white/20'}`}>
            <div className="flex flex-col sm:flex-row justify-between sm:items-center gap-4 mb-4">
                <div>
                    <h2 className="text-xl font-bold text-white">{title}</h2>
                    <div className="text-xs text-gray-300 flex flex-wrap gap-x-3 gap-y-1 mt-1">
                        <span>Arch: <span className="font-semibold text-gray-200">{config.architecture.toUpperCase()}</span></span>
                        <span>LR Schedule: <span className="font-semibold text-gray-200">{getScheduleName(config.lrSchedule)}</span></span>
                        <span>Initial LR: <span className="font-semibold text-gray-200">{config.learningRate}</span></span>
                        <span>Epochs: <span className="font-semibold text-gray-200">{config.epochs}</span></span>
                        {config.dropoutRate > 0 && <span>Dropout: <span className="font-semibold text-gray-200">{config.dropoutRate}</span></span>}
                        {modelInfo && <span>Params: <span className="font-semibold text-gray-200">{modelInfo.totalParams.toLocaleString()}</span></span>}
                        {pruning && <span>Sparsity: <span className="font-semibold text-gray-200">{(pruning.sparsity * 100).toFixed(0)}%</span></span>}
                        {effectiveParams !== null && (
                            <span>Effective Params: <span className="font-semibold text-cyan-300">{effectiveParams.toLocaleString()}</span></span>
                        )}
                        {accuracyDiff !== null && (
                             <span>Validation Acc. vs Unpruned: <span className={`font-semibold ${accuracyDiff >= 0 ? 'text-green-400' : 'text-red-400'}`}>
                                {accuracyDiff >= 0 ? '+' : ''}{(accuracyDiff * 100).toFixed(2)}%
                            </span></span>
                        )}
                    </div>
                </div>
                {!isLive && (
                     <div className="flex flex-col sm:flex-row gap-2">
                        {onTestModel && (
                            <button
                                onClick={onTestModel}
                                className={`font-bold py-2 px-4 rounded-full flex items-center justify-center space-x-2 transition-all duration-300 transform hover:scale-105 text-sm ${isModelInTest ? 'bg-pink-500 text-white' : 'bg-white/20 hover:bg-white/30 text-white'}`}
                            >
                                <RocketIcon className="w-4 h-4"/>
                                <span>{isModelInTest ? 'Currently Testing' : 'Test Model'}</span>
                            </button>
                        )}
                        {onVisualizeModel && (
                             <button
                                onClick={onVisualizeModel}
                                className="font-bold py-2 px-4 rounded-full flex items-center justify-center space-x-2 transition-all duration-300 transform hover:scale-105 text-sm bg-white/20 hover:bg-white/30 text-white"
                            >
                                <EyeIcon className="w-4 h-4"/>
                                <span>Visualize</span>
                            </button>
                        )}
                        {onPruneModel && config.architecture === 'dense' && (
                             <button
                                onClick={() => onPruneModel(props.run as FullTrainingRun)}
                                className="font-bold py-2 px-4 rounded-full flex items-center justify-center space-x-2 transition-all duration-300 transform hover:scale-105 text-sm bg-white/20 hover:bg-white/30 text-white"
                            >
                                <CutIcon className="w-4 h-4"/>
                                <span>Prune & Fine-Tune</span>
                            </button>
                        )}
                    </div>
                )}
            </div>

             {isLive && <div className="mb-6">
                <div className="flex justify-between mb-1">
                    <span className="text-base font-medium text-cyan-300">{status}</span>
                    <span className="text-sm font-medium text-cyan-300">{trainingLog.length} / {config.epochs} Epochs</span>
                </div>
                <div className="w-full bg-gray-700 rounded-full h-2.5">
                    <div className="bg-gradient-to-r from-cyan-400 to-pink-500 h-2.5 rounded-full transition-all duration-500" style={{ width: `${progress}%` }}></div>
                </div>
            </div>}

            {currentAccuracy !== null && (
                <div className="mb-4 text-center bg-black/20 p-2 rounded-lg">
                    <span className="text-lg font-semibold text-gray-200">
                        {isLive ? 'Current ' : 'Final '}
                        {hasValidationData ? 'Validation Accuracy' : 'Accuracy'}: 
                    </span>
                    <span className="text-lg font-bold text-cyan-300">{(currentAccuracy * 100).toFixed(2)}%</span>
                </div>
            )}

            {modelInfo && (
                <details className="mb-6 bg-black/20 rounded-lg border border-white/10 group">
                    <summary className="p-3 flex justify-between items-center cursor-pointer list-none text-gray-300 hover:text-white">
                        <span className="font-semibold flex items-center space-x-2">
                            <InfoIcon className="w-4 h-4" />
                            <span>Model Architecture & Parameters</span>
                        </span>
                        <ChevronDownIcon className="w-5 h-5 transition-transform transform group-open:rotate-180" />
                    </summary>
                    <div className="p-4 border-t border-white/10">
                        <div className="overflow-x-auto">
                            <table className="w-full text-left text-sm">
                                <thead className="text-xs text-gray-400 uppercase">
                                    <tr>
                                        <th className="py-2 px-3">Layer (Type)</th>
                                        <th className="py-2 px-3">Output Shape</th>
                                        <th className="py-2 px-3">Param #</th>
                                        <th className="py-2 px-3">Calculation</th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-gray-700">
                                    {modelInfo.layerCalcs.map((layer, index) => (
                                        <tr key={index}>
                                            <td className="py-2 px-3 font-mono">{layer.name} ({layer.type})</td>
                                            <td className="py-2 px-3 font-mono">{layer.outputShape}</td>
                                            <td className="py-2 px-3 font-mono">{layer.params.toLocaleString()}</td>
                                            <td className="py-2 px-3 text-gray-400 text-xs">{layer.calculation}</td>
                                        </tr>
                                    ))}
                                </tbody>
                                <tfoot>
                                    <tr className="font-bold border-t-2 border-white/20">
                                        <td colSpan={2} className="py-2 px-3 text-right">Total Parameters</td>
                                        <td className="py-2 px-3 font-mono">{modelInfo.totalParams.toLocaleString()}</td>
                                        <td></td>
                                    </tr>
                                </tfoot>
                            </table>
                        </div>
                    </div>
                </details>
            )}


            <div className="flex flex-col gap-8">
                <div className="bg-black/20 p-4 rounded-xl">
                    <h3 className="text-lg font-semibold text-gray-200 mb-4 text-center">Performance vs. Learning Rate</h3>
                    <ResponsiveContainer width="100%" height={350}>
                        <LineChart data={trainingLog} margin={{ top: 5, right: 20, left: -10, bottom: 5 }}>
                            <CartesianGrid strokeDasharray="3 3" stroke="rgba(255, 255, 255, 0.2)" />
                            <XAxis 
                                dataKey="epoch" 
                                stroke="rgba(255, 255, 255, 0.7)" 
                                name="Epoch" 
                                type="number"
                                domain={[1, config.epochs]}
                                allowDataOverflow={true}
                            />
                            <YAxis yAxisId="left" stroke="rgba(255, 255, 255, 0.7)" domain={[0, 0.55]} allowDataOverflow={true} />
                            <YAxis yAxisId="right" orientation="right" stroke="rgba(255, 255, 255, 0.7)" tickFormatter={(val) => val.toExponential(1)} domain={[0, config.learningRate * 1.1]} allowDataOverflow={true} />
                            <Tooltip
                                contentStyle={{
                                    backgroundColor: 'rgba(30, 41, 59, 0.8)',
                                    borderColor: 'rgba(255, 255, 255, 0.3)',
                                }}
                            />
                            <Legend />
                            <Line yAxisId="left" type="monotone" dataKey="loss" stroke="#f472b6" strokeWidth={2} dot={false} name="Training Loss" isAnimationActive={false}/>
                            <Line yAxisId="left" type="monotone" dataKey="val_loss" stroke="#f97316" strokeWidth={2} dot={false} name="Validation Loss" isAnimationActive={false} connectNulls />
                            <Line yAxisId="right" type="monotone" dataKey="lr" stroke="#8884d8" strokeWidth={2} dot={false} name="Learning Rate" isAnimationActive={false} />
                        </LineChart>
                    </ResponsiveContainer>
                </div>
                <div className="bg-black/20 p-4 rounded-xl">
                    <h3 className="text-lg font-semibold text-gray-200 mb-4 text-center">Accuracy</h3>
                    <ResponsiveContainer width="100%" height={350}>
                        <LineChart data={trainingLog} margin={{ top: 5, right: 20, left: -10, bottom: 5 }}>
                            <CartesianGrid strokeDasharray="3 3" stroke="rgba(255, 255, 255, 0.2)" />
                            <XAxis 
                                dataKey="epoch" 
                                stroke="rgba(255, 255, 255, 0.7)" 
                                type="number"
                                domain={[1, config.epochs]}
                                allowDataOverflow={true}
                            />
                            <YAxis 
                                stroke="rgba(255, 255, 255, 0.7)" 
                                tickFormatter={(value) => `${(value * 100).toFixed(0)}%`}
                                domain={[0.65, 1]}
                                allowDataOverflow={true}
                             />
                            <Tooltip
                                contentStyle={{
                                    backgroundColor: 'rgba(30, 41, 59, 0.8)',
                                    borderColor: 'rgba(255, 255, 255, 0.3)',
                                }}
                                formatter={(value: number) => `${(value * 100).toFixed(2)}%`}
                            />
                            <Legend />
                            <Line type="monotone" dataKey="accuracy" stroke="#22d3ee" strokeWidth={2} dot={false} name="Training Accuracy" isAnimationActive={false} />
                            <Line type="monotone" dataKey="val_accuracy" stroke="#4ade80" strokeWidth={2} dot={false} name="Validation Accuracy" isAnimationActive={false} connectNulls />
                        </LineChart>
                    </ResponsiveContainer>
                </div>
            </div>
        </div>
    );
};

import React, { useState, useCallback, useEffect, useRef } from 'react';
import type * as tf from '@tensorflow/tfjs';
import { TrainingConfigurator } from './components/TrainingConfigurator';
import { TrainingDashboard } from './components/TrainingDashboard';
import { InferenceTester } from './components/InferenceTester';
import { Header } from './components/Header';
import { ModelVisualizer } from './components/ModelVisualizer';
import { InfoModal } from './components/InfoModal';
import { WaveScape } from './components/WaveScape';
import { PruningModal } from './components/PruningModal';
import { createModel, trainModel, saveModel, loadModel, checkForSavedModel, deleteSavedModel, downloadModel, pruneModel } from './services/modelService';
import { MnistData } from './services/mnistData';
import type { ModelConfig, TrainingLog, ModelInfo, PruningInfo } from './types';
import { BrainCircuitIcon, PlayIcon, RocketIcon, SaveIcon, FolderDownIcon, TrashIcon, DownloadIcon, XIcon } from './constants';
import { analyzeModel } from './services/modelAnalysisService';
// Info Modal Content
import { AboutInfo } from './components/info-content/AboutInfo';
import { ArchitectureInfo } from './components/info-content/ArchitectureInfo';
import { LayersInfo } from './components/info-content/LayersInfo';
import { LearningRateInfo } from './components/info-content/LearningRateInfo';
import { EpochsBatchSizeInfo } from './components/info-content/EpochsBatchSizeInfo';

export interface TrainingRun {
    id: number;
    config: ModelConfig;
    log: TrainingLog[];
    model: tf.Sequential | null;
    modelInfo: ModelInfo | null;
    pruning?: PruningInfo;
    inputShape?: (number | null)[];
    modelJSON?: object;
}

const MAX_COMPLETED_RUNS = 3;

type Page = 'mnist' | 'wavescape';

const App: React.FC = () => {
    const [page, setPage] = useState<Page>('mnist');
    const [config, setConfig] = useState<ModelConfig>({
        layers: [{ units: 128, activation: 'relu' }],
        learningRate: 0.005,
        lrSchedule: 'cosine',
        epochs: 10,
        batchSize: 512,
        architecture: 'dense',
        dropoutRate: 0.25,
    });
    const [isTraining, setIsTraining] = useState(false);
    const [trainingLog, setTrainingLog] = useState<TrainingLog[]>([]);
    const [modelForTesting, setModelForTesting] = useState<tf.Sequential | null>(null);
    const [modelToVisualize, setModelToVisualize] = useState<tf.Sequential | null>(null);
    const [trainingStatus, setTrainingStatus] = useState('Ready to train.');
    const [savedModelExists, setSavedModelExists] = useState(false);
    const [completedRuns, setCompletedRuns] = useState<TrainingRun[]>([]);
    const [activeInfoModal, setActiveInfoModal] = useState<string | null>(null);
    const [currentModelInfo, setCurrentModelInfo] = useState<ModelInfo | null>(null);
    const [runToPrune, setRunToPrune] = useState<TrainingRun | null>(null);
    const stopTrainingRef = useRef(false);

    useEffect(() => {
        const checkModel = async () => {
            const exists = await checkForSavedModel();
            setSavedModelExists(exists);
        };
        checkModel();
    }, []);

    const handleStopTraining = useCallback(() => {
        stopTrainingRef.current = true;
        setTrainingStatus('Stopping training...');
    }, []);

    const runTrainingProcess = useCallback(async (
        modelToTrain: tf.Sequential,
        configForRun: ModelConfig,
        pruningInfo?: PruningInfo
    ) => {
        // Reset state for the new live run
        setIsTraining(true);
        setTrainingLog([]);
        setCurrentModelInfo(null);
        setModelForTesting(null);
        setTrainingStatus('Initializing...');
        stopTrainingRef.current = false;

        const currentRunLog: TrainingLog[] = [];
        let model = modelToTrain;
        let modelInfo: ModelInfo | null = null;

        try {
            modelInfo = analyzeModel(model, configForRun);
            setCurrentModelInfo(modelInfo);

            setTrainingStatus('Loading MNIST dataset...');
            const data = await MnistData.getInstance();
            const { images: trainImages, labels: trainLabels } = data.getTrainData();
            const { images: testImages, labels: testLabels } = data.getValidationData();

            setTrainingStatus('Starting training...');
            await trainModel(
                model,
                trainImages,
                trainLabels,
                testImages,
                testLabels,
                configForRun,
                async (epoch, logs, lr) => {
                    if (stopTrainingRef.current && model) {
                        model.stopTraining = true;
                    }
                    const newLogEntry: TrainingLog = {
                        epoch: epoch + 1,
                        loss: logs.loss,
                        accuracy: logs.acc,
                        val_loss: logs.val_loss,
                        val_accuracy: logs.val_acc,
                        lr
                    };
                    currentRunLog.push(newLogEntry);

                    // Re-draw the graphs after each epoch is complete to ensure live updates.
                    // We use the spread operator to ensure a new array reference is passed to Recharts.
                    setTrainingLog([...currentRunLog]);

                    // Allow UI to render the new state before proceeding with the next epoch.
                    await new Promise(resolve => requestAnimationFrame(resolve));

                    if (!stopTrainingRef.current) {
                        setTrainingStatus(`Epoch ${epoch + 1}/${configForRun.epochs} complete...`);
                    }
                }
            );

            const finalStatus = stopTrainingRef.current 
                ? 'Training stopped by user.'
                : 'Training complete!';

            setTrainingStatus(finalStatus);

            // Capture metadata BEFORE storing in React state.
            const inputTensorShape = model.inputs[0]?.shape; 
            const inputShape = inputTensorShape ? inputTensorShape.slice(1) : undefined;
            const modelJSON = model.toJSON(null, false) as object;

            setCompletedRuns(prev => {
                const newRun: TrainingRun = {
                    id: Date.now(),
                    config: { ...configForRun },
                    log: [...currentRunLog],
                    model: model,
                    modelInfo: modelInfo,
                    inputShape: inputShape,
                    modelJSON: modelJSON,
                    ...(pruningInfo && { pruning: pruningInfo }),
                };
                const updatedRuns = [newRun, ...prev];
                return updatedRuns.slice(0, MAX_COMPLETED_RUNS);
            });

        } catch (error) {
            console.error('Training failed:', error);
            setTrainingStatus(`Error during training: ${error instanceof Error ? error.message : 'Unknown error'}`);
        } finally {
            setIsTraining(false);
            // Note: We intentionally do NOT clear trainingLog here so it remains visible
            // in the Live Dashboard view until the next training run is started.
        }
    }, []);

    const handleStartTraining = useCallback(async () => {
        const newModel = createModel(config);
        newModel.summary();
        await runTrainingProcess(newModel, config);
    }, [config, runTrainingProcess]);

    const handleStartPruningAndFinetuning = useCallback(async (originalRun: TrainingRun, targetSparsity: number) => {
        setRunToPrune(null); // Close modal
        setTrainingStatus('Pruning model...');
        if (!originalRun.model || !originalRun.inputShape || !originalRun.modelJSON) {
            setTrainingStatus('Error: Original model metadata not available for pruning.');
            return;
        }

        try {
            const { prunedModel, actualSparsity } = await pruneModel(originalRun.model, targetSparsity, originalRun.inputShape, originalRun.modelJSON);
            prunedModel.summary();

            const finetuneConfig: ModelConfig = {
                ...originalRun.config,
                epochs: 5,
                learningRate: 0.0001,
                lrSchedule: 'constant',
            };

            const pruningInfo: PruningInfo = {
                fromRunId: originalRun.id,
                sparsity: actualSparsity
            };

            setTrainingStatus('Starting fine-tuning...');
            await runTrainingProcess(prunedModel, finetuneConfig, pruningInfo);

        } catch (error) {
             console.error('Pruning failed:', error);
            setTrainingStatus(`Error during pruning: ${error instanceof Error ? error.message : 'Unknown error'}`);
        }

    }, [runTrainingProcess]);


    const handleSaveModel = useCallback(async () => {
        if (!modelForTesting) return;
        setTrainingStatus('Saving model to local storage...');
        try {
            await saveModel(modelForTesting);
            setSavedModelExists(true);
            setTrainingStatus('Model saved successfully!');
        } catch (error) {
            console.error('Failed to save model:', error);
            setTrainingStatus(`Error saving model: ${error instanceof Error ? error.message : 'Unknown error'}`);
        }
    }, [modelForTesting]);

    const handleDownloadModel = useCallback(async () => {
        if (!modelForTesting) return;
        setTrainingStatus('Preparing model for download...');
        try {
            await downloadModel(modelForTesting);
            setTrainingStatus('Model download started!');
        } catch (error) {
            console.error('Failed to download model:', error);
            setTrainingStatus(`Error downloading model: ${error instanceof Error ? error.message : 'Unknown error'}`);
        }
    }, [modelForTesting]);

    const handleLoadModel = useCallback(async () => {
        setTrainingStatus('Loading model from local storage...');
        try {
            const loadedModel = await loadModel();
            setModelForTesting(loadedModel);
            setTrainingStatus('Model loaded! Ready for testing.');
        } catch (error) {
            console.error('Failed to load model:', error);
            setTrainingStatus(`Error loading model: ${error instanceof Error ? error.message : 'Unknown error'}`);
        }
    }, []);

    const handleDeleteModel = useCallback(async () => {
        if (window.confirm('Are you sure you want to delete the saved model? This action cannot be undone.')) {
            setTrainingStatus('Deleting saved model...');
            try {
                await deleteSavedModel();
                setSavedModelExists(false);
                setTrainingStatus('Saved model deleted.');
                if(modelForTesting?.name === 'localstorage://mnist-model') {
                    setModelForTesting(null);
                }
            } catch (error) {
                console.error('Failed to delete model:', error);
                setTrainingStatus(`Error deleting model: ${error instanceof Error ? error.message : 'Unknown error'}`);
            }
        }
    }, [modelForTesting]);

    const handleClearRuns = () => {
        setCompletedRuns([]);
        setTrainingLog([]);
        setCurrentModelInfo(null);
        setModelForTesting(null);
    }

    const handlePruneRequest = (run: TrainingRun) => {
        setRunToPrune(run);
    };

    const handleShowInfo = (topic: string) => setActiveInfoModal(topic);
    const handleCloseInfo = () => setActiveInfoModal(null);

    const renderInfoModal = () => {
        if (!activeInfoModal) return null;

        let title = '';
        let content: React.ReactNode = null;

        switch (activeInfoModal) {
            case 'about':
                title = 'About This App';
                content = <AboutInfo />;
                break;
            case 'architecture':
                title = 'Understanding Model Architectures';
                content = <ArchitectureInfo />;
                break;
            case 'layers':
                title = 'Hidden Layers, Units, and Activations';
                content = <LayersInfo />;
                break;
            case 'lr':
                title = 'The Learning Rate & Schedules';
                content = <LearningRateInfo />;
                break;
            case 'epochs-batch':
                title = 'Epochs & Batch Size';
                content = <EpochsBatchSizeInfo />;
                break;
            default:
                return null;
        }

        return (
            <InfoModal title={title} onClose={handleCloseInfo}>
                {content}
            </InfoModal>
        );
    };

    const isIdle = !isTraining && trainingLog.length === 0 && completedRuns.length === 0;

    const renderMnistExplorer = () => (
        <main className="w-full max-w-7xl mx-auto grid grid-cols-1 lg:grid-cols-3 gap-8 mt-8">
            <div className="lg:col-span-1 space-y-8">
                <TrainingConfigurator 
                    config={config} 
                    setConfig={setConfig} 
                    onStartTraining={handleStartTraining} 
                    onStopTraining={handleStopTraining}
                    isTraining={isTraining} 
                    onShowInfo={handleShowInfo}
                />
                {savedModelExists && (
                     <div className="bg-white/10 border border-white/20 rounded-2xl p-6 space-y-4 shadow-2xl">
                        <h2 className="text-xl font-bold text-white">Manage Saved Model</h2>
                        <p className="text-sm text-gray-300">A trained model is available in your browser's local storage.</p>
                        <div className="flex flex-col sm:flex-row gap-4">
                            <button 
                                onClick={handleLoadModel} 
                                disabled={isTraining}
                                className="flex-1 bg-gradient-to-r from-green-500 to-emerald-500 hover:from-green-400 hover:to-emerald-400 text-white font-bold py-2 px-4 rounded-full flex items-center justify-center space-x-2 transition-all duration-300 transform hover:scale-105 disabled:opacity-50 disabled:cursor-wait"
                            >
                                <FolderDownIcon className="w-5 h-5"/>
                                <span>Load Model</span>
                            </button>
                            <button 
                                onClick={handleDeleteModel} 
                                disabled={isTraining}
                                className="flex-1 bg-gradient-to-r from-red-500 to-pink-500 hover:from-red-400 hover:to-pink-400 text-white font-bold py-2 px-4 rounded-full flex items-center justify-center space-x-2 transition-all duration-300 transform hover:scale-105 disabled:opacity-50"
                            >
                                <TrashIcon className="w-5 h-5"/>
                                <span>Delete Model</span>
                            </button>
                        </div>
                    </div>
                )}
            </div>
            <div className="lg:col-span-2 space-y-8">
                {isIdle ? (
                    <div className="bg-white/10 border border-white/20 rounded-2xl p-8 h-full flex flex-col justify-center items-center text-center shadow-2xl">
                        <BrainCircuitIcon className="w-24 h-24 text-cyan-300 mb-6" />
                        <h2 className="text-3xl font-bold mb-2 bg-clip-text text-transparent bg-gradient-to-r from-cyan-400 to-pink-500">Welcome to the ML Explorer</h2>
                        <p className="text-gray-300 max-w-md">Configure your neural network on the left, then click 'Start Training' to see it learn{savedModelExists && ", or load a previously saved model"}!</p>
                        {!isTraining && (
                            <button
                                onClick={handleStartTraining}
                                className="mt-8 bg-gradient-to-r from-cyan-500 to-blue-500 hover:from-cyan-400 hover:to-blue-400 text-white font-bold py-3 px-8 rounded-full flex items-center space-x-2 transition-all duration-300 transform hover:scale-105 shadow-lg"
                            >
                                <PlayIcon className="w-5 h-5" />
                                <span>Start First Training</span>
                            </button>
                        )}
                    </div>
                ) : (
                  <>
                    {(isTraining || trainingLog.length > 0) && (
                        <TrainingDashboard 
                            isLive={true}
                            trainingLog={trainingLog} 
                            config={config}
                            status={trainingStatus}
                            modelInfo={currentModelInfo}
                        />
                    )}

                    {completedRuns.length > 0 && (
                        <div className="flex justify-between items-center mt-12 mb-4">
                            <h2 className="text-2xl font-bold text-white">Comparison Runs</h2>
                            <button onClick={handleClearRuns} className="flex items-center space-x-2 text-sm text-gray-400 hover:text-red-400 transition">
                                <TrashIcon className="w-4 h-4" />
                                <span>Clear All History</span>
                            </button>
                        </div>
                    )}

                    {completedRuns.map(run => {
                        const parentRun = run.pruning
                            ? completedRuns.find(p => p.id === run.pruning!.fromRunId)
                            : undefined;
                        return (
                            <TrainingDashboard 
                                key={run.id}
                                isLive={false}
                                run={run}
                                parentRun={parentRun}
                                onTestModel={() => setModelForTesting(run.model)}
                                onVisualizeModel={() => setModelToVisualize(run.model)}
                                isModelInTest={modelForTesting === run.model}
                                onPruneModel={handlePruneRequest}
                            />
                        );
                    })}
                  </>
                )}
                {modelForTesting && (
                   <div className="bg-white/10 border border-white/20 rounded-2xl p-8 shadow-2xl">
                     <div className="flex flex-col sm:flex-row items-center justify-between space-y-4 sm:space-y-0 sm:space-x-4 mb-6">
                       <div className="flex items-center space-x-4">
                         <RocketIcon className="w-10 h-10 text-pink-400" />
                         <div>
                           <h2 className="text-2xl font-bold text-white">Test Your Model</h2>
                           <p className="text-gray-300">Draw digits on the canvases below to see your model in action.</p>
                         </div>
                       </div>
                       <div className="flex flex-col sm:flex-row gap-3">
                        <button 
                            onClick={handleSaveModel}
                            className="w-full sm:w-auto bg-gradient-to-r from-violet-500 to-fuchsia-500 hover:from-violet-400 hover:to-fuchsia-400 text-white font-bold py-2 px-6 rounded-full flex items-center justify-center space-x-2 transition-all duration-300 transform hover:scale-105"
                        >
                            <SaveIcon className="w-5 h-5" />
                            <span>Save Model</span>
                        </button>
                        <button 
                            onClick={handleDownloadModel}
                            className="w-full sm:w-auto bg-gradient-to-r from-blue-500 to-teal-500 hover:from-blue-400 hover:to-teal-400 text-white font-bold py-2 px-6 rounded-full flex items-center justify-center space-x-2 transition-all duration-300 transform hover:scale-105"
                        >
                            <DownloadIcon className="w-5 h-5" />
                            <span>Download Model</span>
                        </button>
                        <button onClick={() => setModelForTesting(null)} className="w-full sm:w-auto bg-gray-600 hover:bg-gray-500 text-white font-bold py-2 px-6 rounded-full flex items-center justify-center space-x-2 transition-all duration-300">
                            <XIcon className="w-5 h-5" />
                            <span>Close</span>
                        </button>
                       </div>
                     </div>
                     <InferenceTester model={modelForTesting} />
                   </div>
                )}
            </div>
        </main>
    );

    const renderWaveScape = () => (
         <main className="w-full max-w-7xl mx-auto flex flex-col items-center gap-8 mt-8 px-4">
            <div className="text-center">
                <h2 className="text-3xl font-bold mb-2 bg-clip-text text-transparent bg-gradient-to-r from-teal-400 to-sky-500">Interactive Gradient Descent</h2>
                <p className="text-gray-300 max-w-3xl">
                    Explore advanced optimization techniques in a visual sandbox. The ball navigates a complex, procedurally generated loss landscape full of hills, valleys, and saddle points, trying to find the lowest point. Each time you press "New Landscape," a unique challenge is created. Go beyond simple gradient descent: switch to the powerful Adam optimizer, use the "Continuation" method to smooth the landscape, and add thermal noise with Langevin Dynamics to escape local minima. Experiment with these powerful tools to see how modern optimizers conquer challenging problems.
                </p>
            </div>
            <WaveScape />
          </main>
    );

    return (
        <div 
            className="min-h-screen w-full bg-black bg-cover bg-center bg-fixed text-white font-sans" 
            style={{ backgroundImage: `url('https://files.catbox.moe/w544w8.webp')` }}
        >
            {renderInfoModal()}

            {runToPrune && (
                <PruningModal 
                    run={runToPrune}
                    onClose={() => setRunToPrune(null)}
                    onStartFinetuning={handleStartPruningAndFinetuning}
                />
            )}

            {modelToVisualize ? (
